import { TypeQuizQuestion } from "./quiz-types";
export const newQType6: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 951, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 6 is offered an exciting new job. Their first reaction is:", options: [{ letter: "A", text: "Accept immediately without hesitation" }, { letter: "B", text: "Start mentally cataloging everything that could go wrong, What if I'm not good enough? What if the company fails?" }, { letter: "C", text: "Negotiate for the highest salary" }, { letter: "D", text: "Ask how it will make them look" }], answer: "B", explanation: "Sixes' minds automatically generate worst-case scenarios. Even positive opportunities are filtered through a threat-detection system that asks 'What could go wrong?' before celebrating what could go right." },
  { id: 952, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "A Type 6 hears a strange noise at night in their house. They:", options: [{ letter: "A", text: "Roll over and go back to sleep" }, { letter: "B", text: "Lie awake running through every possible explanation, from a branch hitting the window to an intruder, before deciding whether to investigate" }, { letter: "C", text: "Immediately call the police" }, { letter: "D", text: "Ignore it because they don't want to deal with conflict" }], answer: "B", explanation: "The Six mind is a worst-case-scenario generator. Their inner committee debates every possibility simultaneously, weighing threats from most to least likely. This thorough threat assessment can be paralyzing but also makes them exceptionally prepared." },
  { id: 953, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 6 receives unexpected good news, they often:", options: [{ letter: "A", text: "Celebrate wholeheartedly" }, { letter: "B", text: "Feel a flash of joy immediately followed by suspicion, 'What's the catch?'" }, { letter: "C", text: "Downplay it to seem humble" }, { letter: "D", text: "Share it with everyone immediately" }], answer: "B", explanation: "Sixes distrust good fortune because their nervous system is wired for vigilance. Unexpected positivity triggers suspicion: 'If I let my guard down, that's exactly when something bad will happen.' Joy feels dangerous because it lowers defenses." },
  { id: 954, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "How does a Type 6 typically handle uncertainty?", options: [{ letter: "A", text: "They embrace it with excitement" }, { letter: "B", text: "They try to resolve it immediately, researching, asking trusted advisors, and creating contingency plans" }, { letter: "C", text: "They ignore it" }, { letter: "D", text: "They get angry" }], answer: "B", explanation: "Uncertainty is the Six's kryptonite. Their mind cannot rest while a question is unresolved, so they seek information, consult authorities, and build backup plans. The goal isn't to eliminate risk, it's to feel prepared for every possibility." },
  { id: 955, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which fictional character best exemplifies the Type 6 pattern of loyalty, anxiety, and courage despite fear?", options: [{ letter: "A", text: "James Bond" }, { letter: "B", text: "Samwise Gamgee from Lord of the Rings" }, { letter: "C", text: "Don Draper from Mad Men" }, { letter: "D", text: "Walter White from Breaking Bad" }], answer: "B", explanation: "Samwise is the quintessential Six: fiercely loyal, anxious but courageous, devoted to his chosen authority (Frodo), always preparing for the worst, and finding his greatest strength through commitment to someone he trusts." },
  { id: 956, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "Which Disney character shows Type 6 patterns of catastrophic thinking and risk-assessment?", options: [{ letter: "A", text: "Elsa from Frozen" }, { letter: "B", text: "Marlin from Finding Nemo" }, { letter: "C", text: "Simba from The Lion King" }, { letter: "D", text: "Rapunzel from Tangled" }], answer: "B", explanation: "Marlin is a textbook Six: hypervigilant about danger, catastrophizes constantly, but ultimately musters extraordinary courage when it matters most. His journey from anxiety to bravery IS the Six's growth arc." },
  { id: 957, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which phrase is most characteristic of a Type 6?", options: [{ letter: "A", text: "I need more time alone" }, { letter: "B", text: "But what if something goes wrong?" }, { letter: "C", text: "There's a right way to do this" }, { letter: "D", text: "How does this make me look?" }], answer: "B", explanation: "This phrase captures the Six's core orientation: anticipatory anxiety. Their mind naturally gravitates toward potential problems. It's not pessimism, it's a finely tuned risk-detection system that's always running in the background." },
  { id: 958, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which behavior most suggests someone is a Type 6?", options: [{ letter: "A", text: "Making decisions quickly and independently" }, { letter: "B", text: "Asking multiple trusted people for their opinion before making a decision" }, { letter: "C", text: "Focusing on how they appear to others" }, { letter: "D", text: "Seeking the most unique option" }], answer: "B", explanation: "Sixes don't trust their own judgment easily. They build consensus by consulting their 'inner circle', the trusted people whose opinions anchor them. This isn't indecisiveness; it's a security-seeking strategy that tests ideas against multiple perspectives." },
  { id: 959, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which internal monologue is most typical for a Type 6?", options: [{ letter: "A", text: "What's the most exciting option?" }, { letter: "B", text: "Can I trust this? What's really going on here?" }, { letter: "C", text: "How can I help?" }, { letter: "D", text: "What's the most efficient approach?" }], answer: "B", explanation: "The Six's mind operates as a truth-verification system. They constantly scan for hidden agendas, underlying motives, and unspoken dangers. This isn't paranoia, it's a vigilance pattern that sometimes catches real threats others miss." },
  { id: 960, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "A Type 6 is most likely to say which of these before a road trip?", options: [{ letter: "A", text: "Let's just wing it!" }, { letter: "B", text: "Did we check the tire pressure? Do we have a spare? What's the weather forecast? Is there a hospital near our destination?" }, { letter: "C", text: "I don't care about the details, let's go" }, { letter: "D", text: "I trust that everything will work out" }], answer: "B", explanation: "The Six's pre-trip checklist reveals their core pattern: anticipating and preparing for every potential problem. They're the friend who packs a first-aid kit, checks the route twice, and knows the nearest emergency services. When things go wrong, you want a Six there." },
  { id: 961, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 6s?", options: [{ letter: "A", text: "Having completely trustworthy, consistent caregivers" }, { letter: "B", text: "Experiencing an environment where protection felt unreliable, authority figures were inconsistent, unpredictable, or absent, teaching them that safety can't be taken for granted" }, { letter: "C", text: "Being the center of attention" }, { letter: "D", text: "Being told they were special" }], answer: "B", explanation: "Sixes learned early that the world isn't reliably safe. Whether through parental inconsistency, chaotic home life, or a single betrayal of trust, they internalized: 'I must stay vigilant because the people meant to protect me might not.'" },
  { id: 962, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 6s often:", options: [{ letter: "A", text: "Were fearless risk-takers" }, { letter: "B", text: "Were hyper-alert to shifts in household mood, able to sense when something was 'off' before adults noticed" }, { letter: "C", text: "Ignored rules entirely" }, { letter: "D", text: "Were completely self-focused" }], answer: "B", explanation: "Young Sixes developed extraordinary emotional radar. They learned to detect subtle shifts in tone, mood, and atmosphere, because accurately reading the environment meant anticipating danger and staying safe." },
  { id: 963, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 6 typically ask a question?", options: [{ letter: "A", text: "Directly and without qualification" }, { letter: "B", text: "With built-in hedging and multiple caveats, 'This might be a dumb question, but...' or 'I'm probably overthinking this, but...'" }, { letter: "C", text: "They rarely ask questions" }, { letter: "D", text: "Aggressively and demandingly" }], answer: "B", explanation: "Sixes preface questions with qualifiers to test the social temperature before committing. The hedging isn't insecurity, it's a probe: 'Will this person react negatively? Is it safe to reveal what I don't know?'" },
  { id: 964, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "In group discussions, a Type 6 often plays the role of:", options: [{ letter: "A", text: "The cheerleader who keeps everyone positive" }, { letter: "B", text: "The devil's advocate who spots the flaws in every plan" }, { letter: "C", text: "The silent observer" }, { letter: "D", text: "The person who steers toward action items" }], answer: "B", explanation: "Sixes naturally gravitate toward what could go wrong. They play devil's advocate not to be negative but to stress-test ideas. Their question 'But what about...' has saved many teams from foreseeable disasters." },
  { id: 965, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Type 6's friend hasn't texted back in 24 hours. The Six is most likely thinking:", options: [{ letter: "A", text: "They're probably busy" }, { letter: "B", text: "Running through possibilities: Are they mad at me? Did something happen to them? Did I say something wrong?" }, { letter: "C", text: "Nothing, they don't track other people's responses" }, { letter: "D", text: "I should reach out to someone else" }], answer: "B", explanation: "The Six mind fills uncertainty with scenarios, usually negative ones. A silence that another type wouldn't notice becomes an anxiety-generating void that the Six's imagination fills with potential threats to the relationship." },
  { id: 966, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When a Type 6 succeeds at something, they often:", options: [{ letter: "A", text: "Feel confident they'll succeed again" }, { letter: "B", text: "Attribute it to luck or external factors rather than their own ability, and worry about maintaining the success" }, { letter: "C", text: "Brag about it" }, { letter: "D", text: "Immediately move on without reflection" }], answer: "B", explanation: "Sixes struggle to internalize success. Their doubt extends to their own competence, 'I just got lucky,' 'The test was easy,' 'I had help.' This self-doubt persists regardless of evidence, making each success feel like something that could be taken away." },
  { id: 967, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "Which relationship to authority most suggests a Type 6?", options: [{ letter: "A", text: "Complete indifference to authority" }, { letter: "B", text: "An ambivalent, testing relationship, they want to trust authority but can't help questioning it" }, { letter: "C", text: "Automatic obedience" }, { letter: "D", text: "Constant rebellion without thought" }], answer: "B", explanation: "Sixes have the most complex relationship with authority of any type. They want reliable authority (someone trustworthy to follow) but simultaneously distrust it (authority figures have disappointed them before). This creates the classic Six push-pull with leaders." },
  { id: 968, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "Which statement reveals the Six's core loyalty?", options: [{ letter: "A", text: "I'm loyal to whoever benefits me most" }, { letter: "B", text: "I would do anything for the people I trust, once you're in my inner circle, I'm with you no matter what" }, { letter: "C", text: "I don't believe in loyalty" }, { letter: "D", text: "I'm loyal to my goals above all" }], answer: "B", explanation: "Six loyalty is legendary. Once someone earns their trust (which takes time and testing), the Six's commitment is fierce and unshakable. They'll sacrifice their own comfort for their people, loyalty is the bedrock of Six identity." },
  { id: 969, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Type 6 children often developed strong loyalty to:", options: [{ letter: "A", text: "Whatever was trendy" }, { letter: "B", text: "A specific group, team, or belief system that provided the security and belonging their home environment may have lacked" }, { letter: "C", text: "Only themselves" }, { letter: "D", text: "Material possessions" }], answer: "B", explanation: "Young Sixes seek external anchors: a friend group, a religion, a team, a cause. These become surrogate security systems, stable structures that provide the predictability and belonging that their core anxiety craves." },
  { id: 970, type: 6, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "A Type 6's humor typically features:", options: [{ letter: "A", text: "Gentle, inoffensive jokes" }, { letter: "B", text: "Self-deprecating wit and wry observations about life's absurdities, humor used to defuse anxiety" }, { letter: "C", text: "Slapstick physical comedy" }, { letter: "D", text: "Humor that puts them above others" }], answer: "B", explanation: "Sixes are often brilliantly funny. Their humor comes from the same place as their anxiety: a keen awareness of what could go wrong. They convert anxiety into comedy, making others laugh at the very fears that haunt them." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 971, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In romantic relationships, Type 6s are most at risk of:", options: [{ letter: "A", text: "Being too independent" }, { letter: "B", text: "Testing their partner's loyalty through provocation, unconsciously creating the very abandonment they fear by pushing people to prove they'll stay" }, { letter: "C", text: "Being emotionally unavailable" }, { letter: "D", text: "Moving too fast" }], answer: "B", explanation: "Sixes test loyalty by provoking: 'Will you still love me at my worst?' They create small crises to see if the partner stays. This testing can exhaust partners who feel they're always being auditioned, never truly trusted." },
  { id: 972, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "The Six-Nine pairing is common because:", options: [{ letter: "A", text: "They have identical personalities" }, { letter: "B", text: "The Nine's calm, steady presence soothes the Six's anxiety, while the Six's vigilance provides the structure and protection the Nine often lacks for themselves" }, { letter: "C", text: "They're both highly ambitious" }, { letter: "D", text: "Random chance" }], answer: "B", explanation: "The 6-9 pairing creates complementary security: the Nine's unflappable calm is a balm for Six anxiety, and the Six's alertness compensates for the Nine's tendency to overlook problems. Together they create a stable, if sometimes stagnant, unit." },
  { id: 973, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 6?", options: [{ letter: "A", text: "Repression" }, { letter: "B", text: "Projection, attributing their own fears and hostile impulses to others, then reacting to the projected threat as if it were real" }, { letter: "C", text: "Sublimation" }, { letter: "D", text: "Isolation of affect" }], answer: "B", explanation: "Sixes project their own doubt and hostility outward: their inner critic becomes the harsh boss, their self-doubt becomes others' judgment, their anger becomes others' aggression. They then react to these projections as real external threats." },
  { id: 974, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "The Six's 'doubt' operates as a fixation by:", options: [{ letter: "A", text: "Making them think clearly" }, { letter: "B", text: "Creating an infinite loop, doubting their decisions, then doubting their doubt, then doubting their doubt about their doubt, making certainty permanently unreachable" }, { letter: "C", text: "Helping them avoid mistakes" }, { letter: "D", text: "Having no real effect" }], answer: "B", explanation: "Six doubt is recursive and self-generating: 'Is this right? But what if I'm wrong about it being right? But what if my doubt is just anxiety?' The mind generates doubt about its own conclusions, creating an unbreakable loop that prevents the certainty they crave." },
  { id: 975, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How does a phobic Six typically handle conflict?", options: [{ letter: "A", text: "With direct confrontation" }, { letter: "B", text: "By seeking allies, building coalitions, and approaching conflict from a position of group support rather than solo confrontation" }, { letter: "C", text: "By dominating aggressively" }, { letter: "D", text: "By ignoring it completely" }], answer: "B", explanation: "Phobic Sixes manage conflict through alliance-building. They don't fight alone, they seek strength in numbers, consulting trusted advisors and building consensus before engaging. Safety lies in the group, not in solo bravery." },
  { id: 976, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "How does a counterphobic Six handle conflict?", options: [{ letter: "A", text: "By avoiding it entirely" }, { letter: "B", text: "By charging directly toward the threat, they confront what they fear head-on, sometimes aggressively, as a way of managing anxiety through action" }, { letter: "C", text: "By intellectualizing it" }, { letter: "D", text: "By seeking external authority" }], answer: "B", explanation: "Counterphobic Sixes manage fear by running AT it. Their logic: 'If I confront what scares me, it can't sneak up on me.' This can look like Eight-ish aggression, but the underlying motivation is fear management, not power-seeking." },
  { id: 977, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the Six's deepest fear?", options: [{ letter: "A", text: "Being ordinary" }, { letter: "B", text: "Being without support or guidance, left to face a dangerous, unpredictable world alone without any reliable structure or person to trust" }, { letter: "C", text: "Being incompetent" }, { letter: "D", text: "Being unloved" }], answer: "B", explanation: "The Six's core terror is abandonment in a hostile world. They fear being left without guidance, support, or structure, facing life's chaos alone. This drives their loyalty-seeking, authority-testing, and alliance-building." },
  { id: 978, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "The Six's 'inner committee' refers to:", options: [{ letter: "A", text: "Their friend group" }, { letter: "B", text: "The multiple conflicting voices in their mind, each offering different fears, warnings, and advice, creating an internal parliament that rarely reaches consensus" }, { letter: "C", text: "Their work team" }, { letter: "D", text: "Their family" }], answer: "B", explanation: "Sixes describe their mind as a committee: the worrier, the rebel, the loyalist, the doubter, the worst-case generator, all arguing simultaneously. Decision-making requires navigating this internal parliament, where every voice has veto power." },
  { id: 979, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "Type 6 parents are most likely to:", options: [{ letter: "A", text: "Give their children total freedom without guidance" }, { letter: "B", text: "Be protective and prepare their children for dangers while struggling to balance safety with their child's need for independence" }, { letter: "C", text: "Be emotionally unavailable" }, { letter: "D", text: "Focus only on achievement" }], answer: "B", explanation: "Six parents are devoted protectors who may over-prepare their children for danger. They teach street smarts, contingency planning, and loyalty, but may struggle to let go enough for their children to take healthy risks." },
  { id: 980, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Attachment Style", question: "Which attachment style is most common among Type 6s?", options: [{ letter: "A", text: "Dismissive-avoidant" }, { letter: "B", text: "Anxious-preoccupied or fearful-avoidant, they crave secure attachment but constantly scan for signs of abandonment or betrayal" }, { letter: "C", text: "Secure" }, { letter: "D", text: "No pattern" }], answer: "B", explanation: "Sixes' attachment is defined by vigilance: they want closeness but can't relax into it. They monitor partners for signs of withdrawal, inconsistency, or betrayal, creating the anxious surveillance that can paradoxically push partners away." },
  { id: 981, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Somatic Patterns", question: "Where do Type 6s most commonly hold anxiety in their body?", options: [{ letter: "A", text: "Their heart center" }, { letter: "B", text: "Their gut and solar plexus, the 'pit of the stomach' feeling, along with tension in the jaw, shoulders, and the constant vigilant alertness of the nervous system" }, { letter: "C", text: "Their feet" }, { letter: "D", text: "Nowhere, they don't somatize" }], answer: "B", explanation: "Six anxiety is profoundly somatic: the gut-churning 'something's wrong' feeling, jaw-clenching vigilance, shoulder-tensing alertness, and the perpetually activated fight-or-flight system. Their body is always slightly braced for impact." },
  { id: 982, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Sixes often report that their anxiety:", options: [{ letter: "A", text: "Only appears in specific situations" }, { letter: "B", text: "Has no specific object, it's a free-floating background hum that attaches itself to whatever seems most threatening at the moment" }, { letter: "C", text: "Is completely under their control" }, { letter: "D", text: "Doesn't exist" }], answer: "B", explanation: "Six anxiety is often objectless: a free-floating dread that latches onto whatever is available. If work is fine, relationships become the worry. If relationships are fine, health becomes the worry. The anxiety migrates to fill any vacuum." },
  { id: 983, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Coping Under Stress", question: "When stressed, Type 6s move toward which type's behaviors?", options: [{ letter: "A", text: "Type 4, becoming withdrawn and melancholic" }, { letter: "B", text: "Type 3, becoming image-conscious, competitive, and workaholic, trying to outrun their anxiety through achievement" }, { letter: "C", text: "Type 8, becoming aggressive" }, { letter: "D", text: "Type 2, becoming people-pleasing" }], answer: "B", explanation: "Under stress, Sixes disintegrate to Three: the loyal team player becomes a competitive self-promoter. They try to outrun anxiety through achievement, 'If I'm successful enough, I'll finally be safe.' This creates uncharacteristic workaholism and image-consciousness." },
  { id: 984, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What does healthy growth look like for a Type 6?", options: [{ letter: "A", text: "Eliminating all anxiety" }, { letter: "B", text: "Moving toward Type 9 qualities: inner peace, trust in the process, and the ability to relax without needing to control outcomes" }, { letter: "C", text: "Becoming more vigilant" }, { letter: "D", text: "Finding perfect authority figures to trust" }], answer: "B", explanation: "In growth, Sixes integrate to Nine: the anxious vigilante finds inner peace. They learn to trust life's process, relax their hypervigilance, and discover that most of what they feared never materializes. They become grounded, calm, and genuinely trusting." },
  { id: 985, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Workplace Archetypes", question: "Which workplace role does a Type 6 most naturally gravitate toward?", options: [{ letter: "A", text: "The solo creative working independently" }, { letter: "B", text: "The reliable team member who anticipates problems, builds strong working relationships, and serves as the group's early warning system" }, { letter: "C", text: "The visionary CEO" }, { letter: "D", text: "The corporate disruptor" }], answer: "B", explanation: "Sixes are the backbone of organizations: reliable, loyal, anticipatory of problems, and deeply committed to their team. They're not the flashiest employees, but they're the ones who keep things running when everything else falls apart." },
  { id: 986, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Workplace Archetypes", question: "A Six's biggest workplace blind spot is:", options: [{ letter: "A", text: "Not being prepared enough" }, { letter: "B", text: "Analysis paralysis, their thorough risk-assessment can slow decision-making to a crawl, and they may resist action until every uncertainty is resolved (which is never)" }, { letter: "C", text: "Being too trusting of leadership" }, { letter: "D", text: "Taking too many risks" }], answer: "B", explanation: "The Six's strength (thorough preparation) becomes their weakness (permanent preparation). They can delay action indefinitely because there's always one more risk to assess. Perfect safety is impossible, but the Six keeps searching for it." },
  { id: 987, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Relationship Dynamics", question: "What makes Type 6s exceptional friends?", options: [{ letter: "A", text: "Their adventurousness" }, { letter: "B", text: "Their unwavering loyalty during crises, they show up when everyone else disappears, and they remember your struggles long after others have moved on" }, { letter: "C", text: "Their carefree attitude" }, { letter: "D", text: "Their social status" }], answer: "B", explanation: "Six loyalty shines brightest in crisis. While fair-weather friends fade, the Six doubles down. They'll drive across town at 2 AM, remember your surgery date without being reminded, and check in weeks after everyone else forgot. Crisis is where Six love becomes visible." },
  { id: 988, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Defense Mechanisms", question: "The Six's 'scanning' pattern means:", options: [{ letter: "A", text: "Reading lots of documents" }, { letter: "B", text: "Constantly monitoring their environment for signs of threat, reading body language, detecting tone shifts, and anticipating others' actions before they happen" }, { letter: "C", text: "Using radar technology" }, { letter: "D", text: "Being detail-oriented at work" }], answer: "B", explanation: "Sixes are perpetual scanners: they read rooms, detect micro-expressions, notice who's quiet, and sense shifts in atmosphere. This hypervigilance is exhausting but genuinely useful, Sixes often detect problems before anyone else does." },
  { id: 989, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Shadow Work", question: "The Six's relationship with authority is complicated because:", options: [{ letter: "A", text: "They love all authority figures" }, { letter: "B", text: "They simultaneously seek and distrust authority, they want someone reliable to trust but fear that anyone in power will ultimately betray or abandon them" }, { letter: "C", text: "They ignore authority completely" }, { letter: "D", text: "They want to BE the authority" }], answer: "B", explanation: "The Six's authority ambivalence is their defining relational pattern: 'I need you to be trustworthy, but I suspect you're not.' They seek, test, challenge, submit to, and rebel against authority in an exhausting cycle that reflects their deepest wound." },
  { id: 990, type: 6, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Childhood Patterns", question: "The Six child who becomes 'counterphobic' develops this coping strategy because:", options: [{ letter: "A", text: "They enjoy danger" }, { letter: "B", text: "Running toward fear feels more controllable than waiting for it to arrive, the counterphobic response is still fear-based, but it manages fear through confrontation rather than avoidance" }, { letter: "C", text: "They're actually not afraid" }, { letter: "D", text: "They're imitating Type 8" }], answer: "B", explanation: "Counterphobic Sixes discovered that waiting for the scary thing was worse than facing it. Their courage isn't the absence of fear, it's fear channeled into action. 'The monster under the bed is less scary if I look' became their operating principle." },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 991, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Spiritual Traditions", question: "In contemplative traditions, the Six's growth path involves:", options: [{ letter: "A", text: "More preparation" }, { letter: "B", text: "Practices of surrender and trust, learning to release the illusion of control and rest in the present moment rather than scanning the future for threats" }, { letter: "C", text: "Intellectual study of theology" }, { letter: "D", text: "Building stronger community" }], answer: "B", explanation: "Sixes need trust practices: surrendering outcomes, sitting with uncertainty, and discovering that the present moment, without scanning for danger, is actually safe. 'Let go and let God' is the Six's hardest and most necessary spiritual instruction." },
  { id: 992, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Spiritual Traditions", question: "The Christian concept of 'faith' as distinct from 'belief' relates to the Six because:", options: [{ letter: "A", text: "Sixes are naturally faithful" }, { letter: "B", text: "Faith is trusting without certainty, the exact opposite of the Six's strategy of seeking certainty before trusting, making genuine faith the Six's most radical spiritual act" }, { letter: "C", text: "They need stronger beliefs" }, { letter: "D", text: "Faith and belief are the same" }], answer: "B", explanation: "Sixes confuse faith with certainty: 'I'll trust when I'm sure.' But faith, by definition, exists in the absence of certainty. The Six's spiritual breakthrough is discovering that trust doesn't require proof, it requires courage." },
  { id: 993, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Enneagram x MBTI", question: "How does a Type 6 ESTJ differ from a Type 6 INFP?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The ESTJ Six channels anxiety into structure, rules, and organizational control; the INFP Six channels anxiety into moral idealism and inner vigilance about living authentically" }, { letter: "C", text: "Only ESTJs can be Sixes" }, { letter: "D", text: "INFPs don't feel anxiety" }], answer: "B", explanation: "Same core anxiety, different strategies. ESTJ Sixes build external structures (rules, procedures, organizations) to contain their fear. INFP Sixes build internal structures (values, principles, ideals) to anchor against uncertainty." },
  { id: 994, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Enneagram x MBTI", question: "A counterphobic Type 6 ESTP can be easily confused with:", options: [{ letter: "A", text: "Type 2" }, { letter: "B", text: "Type 8, because the counterphobic Six charges toward danger with the ESTP's action-orientation, creating someone who looks fearless and aggressive on the surface" }, { letter: "C", text: "Type 4" }, { letter: "D", text: "Type 5" }], answer: "B", explanation: "Counterphobic 6 + ESTP = someone who looks like a textbook Eight: bold, action-oriented, confrontational, and apparently fearless. The difference is that the Eight fights for control, while the counterphobic Six fights against their own fear." },
  { id: 995, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Instinct x Wing Combos", question: "How does a Self-Preservation 6 (SP6) express anxiety?", options: [{ letter: "A", text: "Through social activism" }, { letter: "B", text: "Through warmth and affiliation, SP6 is the counter-type who manages fear by being friendly, building alliances, and creating a network of mutual protection" }, { letter: "C", text: "Through intellectual analysis" }, { letter: "D", text: "Through physical aggression" }], answer: "B", explanation: "SP6 is the counter-type: they manage fear through warmth rather than vigilance. They're friendly, helpful, and alliance-building, managing anxiety by creating a web of mutual support. They can look like Twos because their fear manifests as caring." },
  { id: 996, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Instinct x Wing Combos", question: "A Sexual (SX) Six typically:", options: [{ letter: "A", text: "Avoids all confrontation" }, { letter: "B", text: "Tests strength and loyalty through direct challenge, they're the most counterphobic subtype, confronting fear by becoming intimidating themselves" }, { letter: "C", text: "Is withdrawn and private" }, { letter: "D", text: "Focuses on material security" }], answer: "B", explanation: "SX6 manages fear through strength-display: 'If I'm strong/intimidating enough, nothing can threaten me.' They test people through confrontation, admire those who push back, and can look remarkably like Eights, but their power-display is fear-driven, not lust-driven." },
  { id: 997, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Tritype Deep Dives", question: "The 614 tritype ('The Philosopher') approaches life by:", options: [{ letter: "A", text: "Avoiding deep thought" }, { letter: "B", text: "Combining Six's questioning with One's principled standards and Four's emotional depth, creating someone who wrestles deeply with moral and existential questions" }, { letter: "C", text: "Seeking power" }, { letter: "D", text: "Focusing on entertainment" }], answer: "B", explanation: "The 614 tritype is the existential questioner: Six's doubt meets One's moral seriousness meets Four's emotional depth. They ask the big questions, 'What's true? What's right? What's meaningful?', with a thoroughness that's both admirable and agonizing." },
  { id: 998, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Tritype Deep Dives", question: "The 682 tritype ('The Rescuer') is driven by:", options: [{ letter: "A", text: "Self-interest" }, { letter: "B", text: "The combination of Six's protective loyalty, Eight's assertive power, and Two's desire to help, creating someone who defends the vulnerable with fierce determination" }, { letter: "C", text: "Intellectual curiosity" }, { letter: "D", text: "Creative expression" }], answer: "B", explanation: "The 682 is the guardian tritype: Six's loyalty provides the commitment, Eight's power provides the force, and Two's warmth provides the motivation. These are the people who fight for the underdog with both passion and staying power." },
  { id: 999, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Growth Practices", question: "Why is 'acting before all doubts are resolved' a growth practice for Sixes?", options: [{ letter: "A", text: "It's reckless" }, { letter: "B", text: "It teaches them that they can handle outcomes even without perfect preparation, and that their doubt will never fully resolve, so waiting for certainty is waiting forever" }, { letter: "C", text: "It doesn't help them" }, { letter: "D", text: "It removes their anxiety" }], answer: "B", explanation: "Sixes wait for certainty that never comes. Acting at 70% certainty teaches them the crucial lesson: 'I can handle whatever happens.' Each successful navigation of uncertainty weakens the belief that they need perfect safety before moving." },
  { id: 1000, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Growth Practices", question: "Meditation is particularly challenging for Sixes because:", options: [{ letter: "A", text: "They can't sit still" }, { letter: "B", text: "Quieting the mind removes the vigilance that feels protective, the scanning stops, and the Six experiences the terrifying vulnerability of not monitoring for threats" }, { letter: "C", text: "They find it boring" }, { letter: "D", text: "It's too spiritual" }], answer: "B", explanation: "Meditation asks Sixes to stop scanning, the very activity that feels life-preserving. Sitting with a quiet mind feels like disabling the alarm system. But through practice, they discover that the silence isn't dangerous, it's where trust lives." },
  { id: 1001, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Claudio Naranjo described the Six as:", options: [{ letter: "A", text: "The Perfectionist" }, { letter: "B", text: "The 'paranoid' character, not in the clinical sense, but as someone whose worldview is organized around suspicion, doubt, and the assumption that hidden dangers lurk beneath surface appearances" }, { letter: "C", text: "The Individualist" }, { letter: "D", text: "The Enthusiast" }], answer: "B", explanation: "Naranjo used 'paranoid' in the character-analytic sense: someone who habitually questions surface reality, suspects hidden motives, and operates from the assumption that things aren't as safe as they seem. It's not pathology, it's a perceptual style." },
  { id: 1002, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Panel Wisdom", question: "In Enneagram panels, Type 6s commonly report:", options: [{ letter: "A", text: "Never feeling afraid" }, { letter: "B", text: "Being surprised to learn that other people don't have a constant inner monologue of worst-case scenarios, they assumed everyone's mind worked like theirs" }, { letter: "C", text: "Having perfect self-trust" }, { letter: "D", text: "Being extremely calm" }], answer: "B", explanation: "Sixes are often genuinely shocked to discover that not everyone's mind generates continuous worst-case scenarios. They assumed their internal warning system was universal. Learning that it's type-specific is both relieving ('I'm not crazy') and disorienting ('Wait, most people don't think like this?')." },
  { id: 1003, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Differential Diagnosis", question: "How do you distinguish a Type 6 from a Type 1?", options: [{ letter: "A", text: "They're the same type" }, { letter: "B", text: "Ones are driven by an internal standard of rightness; Sixes are driven by fear of the unknown, the One says 'This is wrong and must be fixed,' the Six says 'This is uncertain and might be dangerous'" }, { letter: "C", text: "Sixes are more moral" }, { letter: "D", text: "Ones are more anxious" }], answer: "B", explanation: "Both types can be dutiful and rule-following, but for different reasons. Ones follow rules because it's right. Sixes follow rules because it's safe. The One's emotion is anger (at wrongness). The Six's emotion is fear (of danger). Same behavior, different engine." },
  { id: 1004, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Differential Diagnosis", question: "A person is anxious, vigilant, and struggles with self-doubt. Could be a 6 or a 4. The differentiator is:", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "The Six's anxiety is about external threats and safety; the Four's anxiety is about identity and self-worth, the Six asks 'Am I safe?' the Four asks 'Am I real?'" }, { letter: "C", text: "Fours don't have anxiety" }, { letter: "D", text: "Sixes don't doubt themselves" }], answer: "B", explanation: "Both types experience anxiety, but about different things. Six anxiety is threat-focused: 'What could go wrong out there?' Four anxiety is identity-focused: 'What's wrong with me in here?' The Six scans the environment; the Four scans the self." },
  { id: 1005, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Workplace Archetypes", question: "A Six with a 7-wing (6w7) in the workplace tends to:", options: [{ letter: "A", text: "Be purely anxious and cautious" }, { letter: "B", text: "Combine risk-awareness with optimistic energy, they see problems but also solutions, making them the team member who says 'Here's what could go wrong, and here's how we fix it'" }, { letter: "C", text: "Avoid all responsibility" }, { letter: "D", text: "Ignore all risks" }], answer: "B", explanation: "6w7 adds Seven's optimism to Six's vigilance. They're the balanced risk-assessor: worried enough to spot problems, upbeat enough to propose solutions. This combination makes exceptional project managers, crisis handlers, and strategists." },
  { id: 1006, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Workplace Archetypes", question: "A Six with a 5-wing (6w5) in the workplace tends to:", options: [{ letter: "A", text: "Be the most social person on the team" }, { letter: "B", text: "Combine vigilance with deep analysis, they become the security expert, the risk analyst, or the person who identifies systemic vulnerabilities others overlooked" }, { letter: "C", text: "Avoid all analytical work" }, { letter: "D", text: "Take constant risks" }], answer: "B", explanation: "6w5 adds Five's analytical depth to Six's threat-detection. They're the deep thinker who spots systemic risks, cybersecurity analysts, strategic planners, or legal experts who see every possible failure mode and document them thoroughly." },
  { id: 1007, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Communication Style", question: "The Six's tendency to 'think out loud' in both directions serves to:", options: [{ letter: "A", text: "Confuse people" }, { letter: "B", text: "Test ideas by voicing both sides, they'll argue for AND against the same position in one conversation, using the listener as a sounding board for their internal debate" }, { letter: "C", text: "Show off their intelligence" }, { letter: "D", text: "Manipulate the listener" }], answer: "B", explanation: "Sixes process by externalizing their inner committee. They'll say 'On one hand... but on the other hand...' because they genuinely see both sides and need to test each against a trusted listener. It's not indecisiveness, it's thorough processing." },
  { id: 1008, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Coping Under Stress", question: "The Six's 'worst-case scenario planning' can actually be helpful because:", options: [{ letter: "A", text: "It's always excessive" }, { letter: "B", text: "It genuinely prepares them for real problems, Sixes are often the first to spot developing crises, and their contingency plans frequently save the day when others were caught off-guard" }, { letter: "C", text: "It makes them seem smarter" }, { letter: "D", text: "It impresses authority" }], answer: "B", explanation: "Six anxiety isn't always dysfunctional, it's a highly tuned detection system. In genuinely dangerous situations (pandemic preparation, emergency planning, risk management), the Six's 'What could go wrong?' thinking is literally life-saving." },
  { id: 1009, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Relationship Dynamics", question: "The 'loyalty test' pattern in Six relationships involves:", options: [{ letter: "A", text: "Formal examinations" }, { letter: "B", text: "Unconsciously creating small crises or provocations to see if the partner stays, each passed test builds trust slightly, but the Six keeps generating new tests" }, { letter: "C", text: "Background checks" }, { letter: "D", text: "Written contracts" }], answer: "B", explanation: "Sixes test loyalty through provocation: being difficult, creating minor conflicts, or withdrawing to see if the partner pursues. Each passed test provides temporary relief, but the doubt-machine generates new tests. Partners can feel they're in an endless audition." },
  { id: 1010, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Emotional Reactions", question: "Why can Sixes appear to switch between warmth and suspicion rapidly?", options: [{ letter: "A", text: "They're manipulative" }, { letter: "B", text: "Their internal doubt operates like a pendulum, the closer they get to someone, the more vulnerable they feel, triggering the doubt that swings them back to suspicion" }, { letter: "C", text: "They have mood disorders" }, { letter: "D", text: "They don't care about consistency" }], answer: "B", explanation: "The Six's warmth-suspicion pendulum is driven by the vulnerability paradox: intimacy creates exposure, exposure creates fear, fear creates suspicion, suspicion creates distance, distance creates longing, longing creates warmth... and the cycle repeats." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 1011, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Oscar Ichazo named the Six's fixation 'cowardice.' In his framework, this means:", options: [{ letter: "A", text: "Physical weakness" }, { letter: "B", text: "Not lack of bravery but the cognitive habit of doubt-as-default, the mind automatically assumes the worst, distrusts its own guidance, and seeks external certainty that can never satisfy" }, { letter: "C", text: "Running from fights" }, { letter: "D", text: "Avoiding responsibility" }], answer: "B", explanation: "Ichazo's 'cowardice' isn't about bravery, it's about the mind's automatic doubt. The Six's cognitive system defaults to distrust: of self, of others, of reality, of good fortune. This isn't a character flaw; it's a perceptual habit that can be changed." },
  { id: 1012, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Six's holy idea in Ichazo's system is 'Holy Faith' (or 'Holy Strength'). This means:", options: [{ letter: "A", text: "Religious faith" }, { letter: "B", text: "The recognition that Being itself is trustworthy, reality supports those who engage with it, and the Six's own inner knowing is a reliable guide when they stop doubting it" }, { letter: "C", text: "Physical strength" }, { letter: "D", text: "Believing harder" }], answer: "B", explanation: "Holy Faith isn't belief in God, it's trust in existence itself. The Six discovers that reality isn't hostile, their own perception isn't unreliable, and their inner guidance is trustworthy. The world has been more supportive than the doubt allowed them to see." },
  { id: 1013, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "In object relations theory, the Six's developmental challenge relates to:", options: [{ letter: "A", text: "Too much security" }, { letter: "B", text: "The 'basic trust' failure, the child needed consistent, reliable protection to develop trust in the world, but received inconsistency, creating a permanent orientation toward threat-detection" }, { letter: "C", text: "Excessive praise" }, { letter: "D", text: "Physical trauma" }], answer: "B", explanation: "Erikson's 'basic trust vs. basic mistrust' maps directly to the Six's wound. When early caregiving was inconsistent (sometimes protective, sometimes absent, sometimes threatening), the child developed a perceptual system organized around anticipating betrayal." },
  { id: 1014, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Object Relations Deep", question: "The Six's relationship to the 'internal persecutor' is:", options: [{ letter: "A", text: "They don't have one" }, { letter: "B", text: "Their internal persecutor is projected outward, they experience their own self-attacking thoughts as coming from the external world, making the world feel threatening when the threat is actually internal" }, { letter: "C", text: "They enjoy it" }, { letter: "D", text: "It makes them stronger" }], answer: "B", explanation: "The Six's internal critic projects outward: their own self-doubt becomes 'they think I'm incompetent,' their own hostility becomes 'they're hostile toward me.' The external world becomes a mirror for internal dangers that have been disowned and projected." },
  { id: 1015, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "Why is the SP6 considered the counter-type?", options: [{ letter: "A", text: "They're fearless" }, { letter: "B", text: "They manage fear through warmth and affiliation rather than vigilance or confrontation, looking un-Six-like because their anxiety manifests as friendliness and relationship-building rather than visible worry" }, { letter: "C", text: "They're identical to other Sixes" }, { letter: "D", text: "They don't experience anxiety" }], answer: "B", explanation: "SP6 hides fear behind warmth. Their anxiety says: 'If I'm friendly and helpful enough, people will protect me.' This makes them the hardest Six to type, they look like Twos or Nines because their fear-management strategy is niceness rather than vigilance." },
  { id: 1016, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Counter-Instinctual Combos", question: "An SX6 with a 5-wing (SX 6w5) creates:", options: [{ letter: "A", text: "A shy, quiet person" }, { letter: "B", text: "An intensely counterphobic person who combines the sexual instinct's strength-testing with the Five-wing's dark intellectualism, they can appear as edgy, rebellious iconoclasts" }, { letter: "C", text: "A stereotypical anxious Six" }, { letter: "D", text: "A warm, friendly person" }], answer: "B", explanation: "SX 6w5 is the most counterphobic combination: sexually driven confrontation + Five-wing's penetrating intelligence + Six's need to test authority = a sharp, provocative, anti-establishment thinker who challenges power structures with intellectual force." },
  { id: 1017, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Historical Enneagram", question: "The Six is sometimes called the 'hardest type to type' because:", options: [{ letter: "A", text: "They're rare" }, { letter: "B", text: "The phobic/counterphobic spectrum and three instinctual variants create such diverse presentations, from the anxious worrier to the aggressive rebel, that Sixes can look like almost any other type" }, { letter: "C", text: "They hide from typing" }, { letter: "D", text: "They all look the same" }], answer: "B", explanation: "Six's diversity is unmatched: phobic Sixes look like Twos or Nines (avoiding danger through pleasantness). Counterphobic Sixes look like Eights (confronting danger through aggression). SP6s look warm, SO6s look dutiful, SX6s look fierce. The common thread, fear, is often invisible." },
  { id: 1018, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Historical Enneagram", question: "The Enneagram's three fear types (5, 6, 7) relate to fear differently. The Six's unique position is:", options: [{ letter: "A", text: "They're the least fearful" }, { letter: "B", text: "They sit directly AT fear, Fives retreat from it into the mind, Sevens escape it into pleasure, but Sixes neither flee nor escape; they live in fear's presence, which is why they're the core fear type" }, { letter: "C", text: "They only fear physical danger" }, { letter: "D", text: "They're identical to 5 and 7" }], answer: "B", explanation: "Six is the pure fear type: they don't intellectualize it (Five) or outrun it (Seven). They live with it. This makes them both the most anxious type and, paradoxically, the most courageous, because they face fear daily rather than avoiding it." },
  { id: 1019, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Integration/Disintegration Chains", question: "When a Six disintegrates to Three, the specific manifestation is:", options: [{ letter: "A", text: "Becoming generous" }, { letter: "B", text: "Abandoning their authentic doubt in favor of a polished, confident persona, they become image-conscious, competitive, and performative, substituting achievement for the trust they can't find" }, { letter: "C", text: "Becoming more relaxed" }, { letter: "D", text: "Increasing their analysis" }], answer: "B", explanation: "Six disintegrating to Three looks like: 'If I can't feel safe, at least I can look successful.' The authentic, questioning Six becomes a performer, replacing genuine trust with the appearance of confidence and replacing inner security with external achievement." },
  { id: 1020, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Integration/Disintegration Chains", question: "When a Six integrates to Nine, the specific transformation is:", options: [{ letter: "A", text: "Becoming apathetic" }, { letter: "B", text: "Finding genuine inner peace, the scanning stops, the doubt quiets, and they discover an internal ground of trust that doesn't depend on external circumstances being safe" }, { letter: "C", text: "Losing their intelligence" }, { letter: "D", text: "Becoming lazy" }], answer: "B", explanation: "Nine-integration for the Six is profound: the relentless inner alarm system finally quiets. They access Nine's acceptance and trust, not passivity, but genuine peace. For the first time, the world feels safe not because threats were eliminated but because inner trust was found." },
  { id: 1021, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo identified that the Six's 'accusation of the other' pattern operates by:", options: [{ letter: "A", text: "Honest confrontation" }, { letter: "B", text: "Projecting their own disowned aggression and distrust onto others, then experiencing the other as hostile, creating a self-fulfilling prophecy where their suspicion provokes the very hostility they feared" }, { letter: "C", text: "Intellectual debate" }, { letter: "D", text: "Silent treatment" }], answer: "B", explanation: "Naranjo observed the Six's projection cycle: they project aggression outward, perceive others as threatening, react defensively, and the defensive reaction provokes actual hostility, which confirms the original projection. The fear creates the threat." },
  { id: 1022, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Differential Diagnosis", question: "A counterphobic 6 and an 8 can look identical. The definitive differentiator is:", options: [{ letter: "A", text: "Physical size" }, { letter: "B", text: "Ask about vulnerability: the Six's aggression covers fear and they know it deep down; the Eight's aggression covers vulnerability but they genuinely don't experience fear in the same way, Eights feel powerful, Sixes feel brave despite fear" }, { letter: "C", text: "Income level" }, { letter: "D", text: "There's no difference" }], answer: "B", explanation: "The acid test: do they feel fear before acting? Eights genuinely don't, they act from lust and power. Counterphobic Sixes feel the fear and charge through it. The Eight says 'I'm not afraid.' The Six says 'I'm terrified, but I'm doing it anyway.'" },
  { id: 1023, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Shadow Work", question: "The Six's 'ambivalence about their own power' stems from:", options: [{ letter: "A", text: "Laziness" }, { letter: "B", text: "The fear that trusting their own strength means they can no longer rely on others for protection, self-trust threatens the alliance system they've built for safety" }, { letter: "C", text: "Physical weakness" }, { letter: "D", text: "Lack of intelligence" }], answer: "B", explanation: "Sixes are often far more capable than they realize, but acknowledging their own power feels dangerous: if they're strong, they can't claim the protection of allies. Self-trust means standing alone, the Six's deepest fear. So they stay doubting, which keeps them needing." },
  { id: 1024, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Growth Practices", question: "Why is 'trusting your gut reaction before analyzing it' transformative for Sixes?", options: [{ letter: "A", text: "Analysis is always wrong" }, { letter: "B", text: "It bypasses the doubt-machine, the Six's first instinct is often correct, but their analytical mind immediately generates counter-arguments that overrule it" }, { letter: "C", text: "Gut reactions are always right" }, { letter: "D", text: "It saves time" }], answer: "B", explanation: "Sixes' initial gut read is frequently accurate, they have excellent instincts. But the doubt-machine immediately starts: 'But what if I'm wrong? What about this other possibility?' Learning to trust their first impression before analysis corrupts it reconnects them to their natural wisdom." },
  { id: 1025, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Tritype Deep Dives", question: "The 694 tritype creates what unique Six variant?", options: [{ letter: "A", text: "An aggressive Six" }, { letter: "B", text: "A deeply introspective, emotionally sensitive Six who combines anxiety with Nine's desire for peace and Four's search for meaning, they seek safety through inner harmony rather than external vigilance" }, { letter: "C", text: "A stereotypical worrier" }, { letter: "D", text: "An extremely social Six" }], answer: "B", explanation: "The 694 adds Nine's peace-seeking and Four's emotional depth to the Six's anxiety. This creates a contemplative, inward-facing Six who manages fear through self-understanding rather than external scanning, the most introspective Six variant." },
  { id: 1026, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Spiritual Traditions", question: "The Twelve-Step concept of 'turning it over to a Higher Power' challenges the Six because:", options: [{ letter: "A", text: "They don't believe in God" }, { letter: "B", text: "It asks for the exact thing their fixation makes impossible: unconditional trust in something they can't verify, control, or prepare against, yet this surrender IS the Six's liberation" }, { letter: "C", text: "It's too simple" }, { letter: "D", text: "They already trust easily" }], answer: "B", explanation: "Surrendering to a Higher Power asks the Six to release control and trust the unverifiable, their kryptonite. But recovery programs have discovered what Enneagram teachers know: the Six's healing comes precisely through the surrender they most resist." },
  { id: 1027, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Attachment Style", question: "How does Six anxiety in relationships differ from anxious attachment in general?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "Six anxiety is specifically about trustworthiness, they don't just fear abandonment but question whether the person's loyalty is genuine, creating a deeper, more systematic distrust than simple attachment anxiety" }, { letter: "C", text: "Six anxiety is less intense" }, { letter: "D", text: "Sixes don't have attachment issues" }], answer: "B", explanation: "Anxious attachment fears abandonment. Six anxiety fears something deeper: deception. An anxiously attached person worries 'Will they leave?' A Six worries 'Is their staying genuine? Are they who they claim to be? Can I trust what I'm seeing?'" },
  { id: 1028, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Parenting Style", question: "The Six parent's greatest growth edge is:", options: [{ letter: "A", text: "Being more protective" }, { letter: "B", text: "Allowing their children to take risks and fail, trusting that their child can handle difficulty without the parent's vigilant intervention" }, { letter: "C", text: "Teaching more survival skills" }, { letter: "D", text: "Finding safer neighborhoods" }], answer: "B", explanation: "Six parents must fight their deepest instinct: to protect against every possible danger. Their growth edge is stepping back and allowing children to fall, fail, and recover, trusting that competence is built through challenge, not prevention." },
  { id: 1029, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Communication Style", question: "In couples therapy, the Six's specific communication challenge is:", options: [{ letter: "A", text: "Talking too much" }, { letter: "B", text: "The tendency to hear threats and accusations in neutral statements, 'We should talk about the finances' becomes 'You think I'm bad with money' through the projection defense" }, { letter: "C", text: "Being too agreeable" }, { letter: "D", text: "Not attending sessions" }], answer: "B", explanation: "The Six's projection transforms neutral input into threatening output. Their partner says 'Let's discuss...' and the Six hears 'You've done something wrong.' This constant misreading creates exhausting patterns where the partner feels they can never say anything safely." },
  { id: 1030, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Somatic Patterns", question: "The Six's nervous system is characterized by:", options: [{ letter: "A", text: "Complete calm" }, { letter: "B", text: "A chronically activated sympathetic nervous system, the fight-or-flight response is perpetually on low simmer, rarely reaching full crisis but never fully deactivating" }, { letter: "C", text: "Excessive relaxation" }, { letter: "D", text: "Normal baseline alertness" }], answer: "B", explanation: "Sixes live in a perpetual state of mild sympathetic activation: not panicking, but never fully at rest. Their nervous system is like a computer with too many background processes, always slightly overloaded, always slightly vigilant, never quite at peace." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 1031, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Ichazo's concept of the Six's 'trap' is 'security.' What does this mean?", options: [{ letter: "A", text: "Security is always good" }, { letter: "B", text: "The Six believes that achieving external security will eliminate their anxiety, but security-seeking IS the anxiety, and no amount of preparation can satisfy a mind that generates infinite threats" }, { letter: "C", text: "They should seek less security" }, { letter: "D", text: "Security is their virtue" }], answer: "B", explanation: "The trap: seeking security seems like the solution but is actually the problem. Each security measure reveals new vulnerabilities. Lock the door? What about the windows? Install cameras? What if they malfunction? The security-seeking IS the anxiety wearing a mask." },
  { id: 1032, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Six's virtue is 'Courage.' In the Enneagram sense, this means:", options: [{ letter: "A", text: "Being fearless" }, { letter: "B", text: "Not the absence of fear but the willingness to act from inner authority while fully experiencing fear, trusting oneself in the face of uncertainty rather than seeking external guarantees" }, { letter: "C", text: "Physical bravery" }, { letter: "D", text: "Fighting others" }], answer: "B", explanation: "Enneagram Courage isn't fearlessness, it's self-trust. The Six's virtue emerges when they stop seeking external certainty and instead act from their own inner knowing, accepting that fear is present but not sovereign. It's the trust they've been seeking outside finally found within." },
  { id: 1033, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "The Six's 'identification with the aggressor' pattern means:", options: [{ letter: "A", text: "They become bullies" }, { letter: "B", text: "They internalize threatening authority figures' voices and attitudes, creating an inner persecutor that attacks them the way the original authority did, and then project this internal attacker back outward onto the world" }, { letter: "C", text: "They admire powerful people" }, { letter: "D", text: "They submit to authority" }], answer: "B", explanation: "Anna Freud's concept maps to the Six: they took in the threatening authority, creating an inner attacker. This internalized persecutor generates the self-doubt, which is then projected outward as world-doubt. The cycle: internalize → attack self → project → see threats everywhere." },
  { id: 1034, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Counter-Instinctual Combos", question: "An SP6 with a 7-wing (SP 6w7) is the most counter-typical Six because:", options: [{ letter: "A", text: "They look fearful" }, { letter: "B", text: "They combine the counter-type's warmth and friendliness with the Seven-wing's optimism, creating someone who appears cheerful, helpful, and easygoing, hiding their anxiety behind a sunny disposition" }, { letter: "C", text: "They're the most anxious" }, { letter: "D", text: "They're aggressive" }], answer: "B", explanation: "SP 6w7 is the hardest Six to identify: the SP counter-type's warmth + Seven's upbeat energy = a friendly, fun person who hides deep anxiety behind positivity. They might be typed as Two, Seven, or Nine before anyone considers Six." },
  { id: 1035, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Historical Enneagram", question: "Gurdjieff's concept of 'self-remembering' is particularly transformative for Sixes because:", options: [{ letter: "A", text: "It improves their memory" }, { letter: "B", text: "It teaches them to be present to themselves rather than scanning the external environment, shifting awareness from 'What's threatening out there?' to 'Who am I, right here, right now?'" }, { letter: "C", text: "It helps them plan better" }, { letter: "D", text: "It reduces their intelligence" }], answer: "B", explanation: "Self-remembering redirects the Six's attention from external scanning to internal presence. Instead of 'What's out there?' the practice asks 'Who's in here?' This shift is revolutionary: it returns the Six to the inner authority they've been seeking externally." },
  { id: 1036, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Integration/Disintegration Chains", question: "The 6-3-9 triangle in the Enneagram reveals that Sixes share the 'attachment' triangle with Threes and Nines. This means:", options: [{ letter: "A", text: "They're identical types" }, { letter: "B", text: "All three types adapted to the external world most directly: the Three through performance, the Nine through merging, and the Six through alliance, each seeking external belonging as a substitute for internal trust" }, { letter: "C", text: "They have the same fears" }, { letter: "D", text: "It's a random grouping" }], answer: "B", explanation: "The 3-6-9 attachment types all shaped themselves around external demands. The Six's strategy, seeking safety through alliances and authority, is the fear-based version of this pattern. All three types need to find internal ground rather than external anchoring." },
  { id: 1037, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Naranjo's Character Types", question: "Naranjo's ultimate insight about the Six is that their fear is:", options: [{ letter: "A", text: "About external danger" }, { letter: "B", text: "Ultimately fear of their own inner authority, they distrust their own perception, judgment, and power, projecting authority outward because taking it back would mean standing alone with their own knowing" }, { letter: "C", text: "About physical harm" }, { letter: "D", text: "Exaggerated by others" }], answer: "B", explanation: "Naranjo's deepest observation: Six fear isn't about the external world, it's about the self. They don't trust their own knowing. All the external vigilance is a displacement of the real issue: 'Can I trust myself?' Reclaiming inner authority dissolves the external scanning." },
  { id: 1038, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Panel Wisdom", question: "Long-time Six practitioners report that their greatest surprise in growth was:", options: [{ letter: "A", text: "That the world became safer" }, { letter: "B", text: "That the world didn't change at all, their perception of it changed, and the same reality that once seemed threatening became supportive when seen through the eyes of self-trust" }, { letter: "C", text: "That they eliminated all anxiety" }, { letter: "D", text: "That they became Nines" }], answer: "B", explanation: "Mature Sixes discover that growth didn't change the world, it changed their relationship with it. The same uncertainty that once terrified them becomes interesting. The same authority they distrusted becomes just another human. Reality was always neutral; fear made it hostile." },
  { id: 1039, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Differential Diagnosis", question: "A person who is loyal, anxious, and authority-conscious could be a 6 or a 1. The deepest differentiator is:", options: [{ letter: "A", text: "They can't be told apart" }, { letter: "B", text: "The One has an internal authority (their inner critic) they trust implicitly; the Six has no internal authority they trust, they seek externally what the One has internalized" }, { letter: "C", text: "Ones don't have anxiety" }, { letter: "D", text: "Sixes don't follow rules" }], answer: "B", explanation: "This is the deepest distinction: Ones have a strong internal authority (the inner critic they obey without question). Sixes LACK internal authority, their doubt extends to their own judgment. The One trusts their inner compass; the Six trusts nothing, including themselves." },
  { id: 1040, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Shadow Work", question: "The Six's ultimate shadow work involves recognizing:", options: [{ letter: "A", text: "More threats" }, { letter: "B", text: "That they have always had the inner authority they were seeking outside, the guidance, strength, and knowing they projected onto trusted others was their own wisdom, externalized because owning it felt too vulnerable" }, { letter: "C", text: "That the world is dangerous" }, { letter: "D", text: "That they need better allies" }], answer: "B", explanation: "The Six's transformative insight: 'The authority I've been seeking in leaders, systems, and allies was inside me all along.' Like Dorothy's ruby slippers, the power to go home was always there. Every quality they admired in trusted others was their own, projected and borrowed back." },
  { id: 1041, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Growth Practices", question: "The practice of 'staying with groundlessness' (Pema Chödrön's teaching) is specifically relevant to Sixes because:", options: [{ letter: "A", text: "They need more grounding" }, { letter: "B", text: "It directly confronts their fixation, instead of seeking ground (security) when anxiety arises, they learn to rest in the anxiety itself, discovering that groundlessness is not dangerous but actually the natural condition of being alive" }, { letter: "C", text: "It's too abstract for Sixes" }, { letter: "D", text: "It increases their anxiety" }], answer: "B", explanation: "Pema Chödrön's teaching is Six medicine: instead of fleeing groundlessness (the Six's reflex), stay. Breathe in the uncertainty. Discover that the falling sensation isn't fatal, it's freedom. The ground the Six has been seeking IS the groundlessness they've been fleeing." },
  { id: 1042, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Tritype Deep Dives", question: "The 612 tritype vs. the 683 tritype represent which two poles of Six expression?", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "The 612 is the warmest, most people-oriented Six (loyal helper with principled heart); the 683 is the most powerful, action-oriented Six (strategic protector who confronts threats head-on)" }, { letter: "C", text: "Both are aggressive" }, { letter: "D", text: "Both are withdrawn" }], answer: "B", explanation: "612 represents the phobic pole of Six: managing fear through alliance, warmth, and principled care. 683 represents the counterphobic pole: managing fear through strength, strategy, and direct confrontation. Same core fear, opposite management styles." },
  { id: 1043, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Spiritual Traditions", question: "The Six's spiritual journey parallels the mythological archetype of:", options: [{ letter: "A", text: "The trickster" }, { letter: "B", text: "The faithful companion who discovers their own heroism, like Samwise, the Six starts as loyal follower and gradually discovers that the courage they attributed to others was their own all along" }, { letter: "C", text: "The lone warrior" }, { letter: "D", text: "The creator" }], answer: "B", explanation: "The Six's mythological arc is the companion-becomes-hero story: they begin as the loyal sidekick, projecting heroism onto the chosen leader. The journey reveals that the courage, wisdom, and authority they admired in others was their own, seen through the mirror of loyalty." },
  { id: 1044, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Instinct x Wing Combos", question: "Rank the six Six subtypes from most phobic to most counterphobic:", options: [{ letter: "A", text: "All are the same" }, { letter: "B", text: "SP 6w5 (most phobic) → SP 6w7 → SO 6w5 → SO 6w7 → SX 6w7 → SX 6w5 (most counterphobic)" }, { letter: "C", text: "SX 6w5 is most phobic" }, { letter: "D", text: "Rankings can't be determined" }], answer: "B", explanation: "Phobic/counterphobic expression correlates with instinct: SP tends most phobic (seeking safety through warmth/alliance), SX tends most counterphobic (seeking safety through strength/confrontation). Wings modify: 5-wing adds more internal processing, 7-wing adds more action." },
  { id: 1045, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Panel Wisdom", question: "Experienced Enneagram teachers note that the Six is often called 'the type that holds everything together' in communities because:", options: [{ letter: "A", text: "They're the most common type" }, { letter: "B", text: "Their loyalty, reliability, and anticipatory problem-solving make them the invisible infrastructure of every functioning group, they're the ones who remember, prepare, show up, and maintain" }, { letter: "C", text: "They're the leaders" }, { letter: "D", text: "They're the most vocal" }], answer: "B", explanation: "Sixes are the social glue of every organization: the person who remembers birthdays, prepares for contingencies, shows up in crises, and maintains the systems everyone else takes for granted. They're infrastructure, invisible but essential." },
  { id: 1046, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Historical Enneagram", question: "The Six's position in the Enneagram as the 'center of the Head triad' means:", options: [{ letter: "A", text: "They're the smartest" }, { letter: "B", text: "They represent the purest expression of the Head center's core issue, the inability to trust one's own inner knowing, while Fives and Sevens represent two different escape routes from this same fundamental doubt" }, { letter: "C", text: "They think the most" }, { letter: "D", text: "They're the most logical" }], answer: "B", explanation: "Six is the archetype of the Head triad: pure doubt. Five escapes doubt by retreating into knowledge. Seven escapes doubt by reframing into optimism. Six stays with doubt, confronting the fundamental question of the Head center: 'Can I trust my own mind?'" },
  { id: 1047, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Naranjo's Character Types", question: "Naranjo observed that the Six's relationship to groups reveals their deepest conflict:", options: [{ letter: "A", text: "They avoid groups" }, { letter: "B", text: "They need groups for safety but fear groups for conformity, creating the perpetual tension of seeking belonging while resisting the loss of individual judgment that belonging requires" }, { letter: "C", text: "They love all groups" }, { letter: "D", text: "They lead all groups" }], answer: "B", explanation: "The Six's group dilemma: they need the safety of belonging but fear the conformity it demands. 'If I join, I lose my independence. If I don't, I'm alone.' This creates the Six's characteristic oscillation between joining and questioning, belonging and rebelling." },
  { id: 1048, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Differential Diagnosis", question: "How do you distinguish a phobic Six from a Type 9?", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "Both appear agreeable and avoidant, but the Six is hypervigilant underneath (scanning for threats while appearing calm) and the Nine is genuinely disengaged (numbing to avoid conflict), one is alert-but-hiding-it, the other is asleep" }, { letter: "C", text: "Nines are more anxious" }, { letter: "D", text: "Sixes are calmer" }], answer: "B", explanation: "The phobic Six and the Nine can look identical on the surface: pleasant, accommodating, non-confrontational. Underneath, they're opposites: the Six is a scanning radar disguised as a relaxed person; the Nine is a genuinely numbed person who has disconnected from their own energy." },
  { id: 1049, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Shadow Work", question: "The Six's relationship with 'the unknown' is unique among Enneagram types because:", options: [{ letter: "A", text: "They love the unknown" }, { letter: "B", text: "Their fixation is fundamentally about the impossibility of ever achieving certainty, the doubt will never resolve because the future is inherently unknowable, making the Six's core strategy (preparation against uncertainty) eternally incomplete" }, { letter: "C", text: "They avoid thinking about it" }, { letter: "D", text: "They've accepted it fully" }], answer: "B", explanation: "The Six's existential dilemma: their entire coping strategy (prepare for uncertainty) can never succeed because the future is inherently uncertain. No amount of preparation eliminates the unknown. This makes the Six's fixation the most philosophically challenging, and their surrender the most profound." },
  { id: 1050, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Growth Practices", question: "The practice of 'leading without external validation' is the Six's equivalent of:", options: [{ letter: "A", text: "A promotion" }, { letter: "B", text: "Flying without a net, it requires them to trust their own judgment without consensus, make decisions without guarantees, and stand behind their choices without an authority to blame if things go wrong" }, { letter: "C", text: "A vacation" }, { letter: "D", text: "Reading a leadership book" }], answer: "B", explanation: "When a Six leads from their own authority, without polling advisors, without seeking consensus, without having a scapegoat ready, they're practicing the ultimate Six growth move. They discover: 'My judgment is reliable. I can trust myself. I am my own authority.'" },
];
